import { FunctionComponent } from 'react';
import { IIconProps } from './types';

/**
 * SVG icon component that renders a vector square (bounding box with corner handles)
 * using an embedded bitmap image pattern. Used to represent selection, grouping,
 * or bounding-box operations within the canvas and node-based UI of the application.
 *
 * @param props - Standard icon props for controlling color, size, style, and opacity.
 */
const VectorSquareSolidIcon: FunctionComponent<IIconProps> = ({
	color,
	height = 50,
	style,
	width = 50,
	opacity = 1,
}) => {
	return (
		<svg
			style={style}
			width={width}
			height={height}
			viewBox="0 0 52 50"
			fill={color}
			opacity={opacity}
			xmlns="http://www.w3.org/2000/svg"
			xmlnsXlink="http://www.w3.org/1999/xlink"
		>
			<rect width={width} height={height} fill="url(#pattern0_444_17557)" />
			<defs>
				<pattern
					id="pattern0_444_17557"
					patternContentUnits="objectBoundingBox"
					width="1"
					height="1"
				>
					<use
						xlinkHref="#image0_444_17557"
						transform="matrix(0.00195312 0 0 0.00202559 0 -0.0185513)"
					/>
				</pattern>
				<image
					id="image0_444_17557"
					width="512"
					height="512"
					xlinkHref="data:image/png;base64,"
				/>
			</defs>
		</svg>
	);
};

export default VectorSquareSolidIcon;
